import React, { useState } from 'react';
import axios from 'axios';
import { Upload, Loader2 } from 'lucide-react';

const CLOUD_NAME = "dwpgncjgn";
const UPLOAD_PRESET = "productos"; 
const API_URL = "http://localhost:5000";

const SubirImagenes = ({ onFinished }) => {
    const [loading, setLoading] = useState(false);

    const handleUpload = async (e) => {
        const files = Array.from(e.target.files);
        if (files.length === 0) return;
        
        setLoading(true);
        try {
            for (const file of files) {
                const formData = new FormData();
                formData.append('file', file);
                formData.append('upload_preset', UPLOAD_PRESET);

                const res = await axios.post(
                    `https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`,
                    formData
                );

                // GUARDAR EN LA DB
                await axios.post(`${API_URL}/api/galeria`, {
                    nombreReferencia: res.data.public_id, // Usamos el ID de Cloudinary
                    publicId: res.data.public_id,
                    url: res.data.secure_url,
                    formato: res.data.format
                });
            }
            alert("¡Imágenes listas para usar!");
            if (onFinished) onFinished();
        } catch (err) {
            console.error(err);
            alert("Error al subir. Revisa que el preset 'productos' sea Unsigned en Cloudinary.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div>
            <input 
                type="file" 
                id="file-input" 
                multiple 
                onChange={handleUpload} 
                style={{ display: 'none' }} 
                accept="image/*"
            />
            <label htmlFor="file-input" style={btnStyle}>
                {loading ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
                {loading ? "Subiendo..." : "Cargar Imágenes"}
            </label>
        </div>
    );
};

const btnStyle = {
    background: '#1e293b', color: 'white', padding: '10px 20px',
    borderRadius: '12px', fontWeight: 'bold', display: 'flex',
    alignItems: 'center', gap: '8px', cursor: 'pointer'
};

export default SubirImagenes;
